import{_ as t,o,c as a,a2 as r}from"./chunks/framework.jWxB9oXr.js";const h=JSON.parse('{"title":"Silvery Architecture","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Silvery Architecture"}],["meta",{"property":"og:description","content":"Silvery Architecture — Silvery documentation."}],["meta",{"property":"og:url","content":"https://silvery.dev/architecture.html"}],["link",{"rel":"canonical","href":"https://silvery.dev/architecture.html"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Silvery Architecture\\",\\"item\\":\\"https://silvery.dev/architecture\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Silvery Architecture\\",\\"description\\":\\"Silvery Architecture — Silvery documentation.\\",\\"url\\":\\"https://silvery.dev/architecture.html\\",\\"dateModified\\":\\"2026-04-09T20:19:33.000Z\\",\\"datePublished\\":\\"2026-04-09T20:19:33.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"]]},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md","lastUpdated":1775765973000}'),i={name:"architecture.md"};function l(n,e,s,c,d,p){return o(),a("div",null,[...e[0]||(e[0]=[r(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /architecture.md for this page in Markdown format</div><h1 id="silvery-architecture" tabindex="-1">Silvery Architecture <a class="header-anchor" href="#silvery-architecture" aria-label="Permalink to &quot;Silvery Architecture&quot;">​</a></h1><p>Silvery is a React framework for terminal UIs. It provides a <a href="https://react.dev/reference/react/Component" class="hover-link" data-tooltip="React&#39;s pluggable rendering backend — Silvery uses a custom reconciler for terminal output" target="_blank" rel="noopener">React reconciler</a>, layout engine, <span class="glossary-hint" data-tooltip="Only re-rendering cells that changed between frames — 100x+ faster than full redraws">incremental rendering</span> pipeline, component library, and theme system. Apps are written as standard React components; silvery handles the terminal.</p><h2 id="rendering-pipeline" tabindex="-1">Rendering Pipeline <a class="header-anchor" href="#rendering-pipeline" aria-label="Permalink to &quot;Rendering Pipeline&quot;">​</a></h2><p>Three phases, <a href="/api/render" class="hover-link" data-tooltip="Sugar over pipe() with sensible defaults — the simplest way to start an app">run</a> on each frame:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>React tree → AgNode tree → Measure → Layout → Render → ANSI output</span></span>
<span class="line"><span>                              ↓          ↓         ↓</span></span>
<span class="line"><span>                          set constraints  positions   incremental</span></span>
<span class="line"><span>                          from props      via Flexily  buffer diff</span></span></code></pre></div><p><strong>Measure</strong> — <a href="https://react.dev/reference/react/Component" class="hover-link" data-tooltip="React&#39;s pluggable rendering backend — Silvery uses a custom reconciler for terminal output" target="_blank" rel="noopener">React reconciler</a> produces an <code>AgNode</code> tree. Each node&#39;s box props (width, height, flex, padding, etc.) become <a href="https://beorn.codes/flexily" class="hover-link" data-tooltip="Pure JavaScript flexbox layout engine — powers Silvery&#39;s layout system" target="_blank" rel="noopener">Flexily</a> layout constraints.</p><p><strong>Layout</strong> — <a href="https://beorn.codes/flexily" class="hover-link" data-tooltip="Pure JavaScript flexbox layout engine — powers Silvery&#39;s layout system" target="_blank" rel="noopener">Flexily</a> (pure JS flexbox, <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a>-compatible) calculates positions and sizes. Results land on <code>AgNode.layout</code> as <code>Rect { x, y, width, height }</code>. Also computes scroll offsets, sticky positions, and screen-relative rects. Components receive layout via <code>useBoxRect()</code> / <code>useScrollRect()</code>.</p><p><strong>Render</strong> — Incremental content <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> to <code>TerminalBuffer</code>. Dirty flags (<code>contentDirty</code>, <code>stylePropsDirty</code>, <code>bgDirty</code>, <code>subtreeDirty</code>, <code>layoutDirty</code>) control which nodes re-<a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>. Previous frame buffer is cloned; only dirty subtrees are re-rendered. Output phase diffs current vs previous buffer to produce minimal <a href="https://terminfo.dev/fundamentals/anatomy" class="hover-link" data-tooltip="Control codes starting with ESC that tell terminals to set colors, move cursor, etc." target="_blank" rel="noopener">ANSI escape</a> sequences.</p><p>The invariant: incremental output must match a fresh (non-incremental) <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>. Verified with <code>SILVERY_STRICT=1</code>.</p><h2 id="key-abstractions" tabindex="-1">Key Abstractions <a class="header-anchor" href="#key-abstractions" aria-label="Permalink to &quot;Key Abstractions&quot;">​</a></h2><p><strong>Term</strong> — The terminal. Wraps a backend (Node.js stdin/stdout, xterm.js, headless) and provides styling, capabilities, dimensions, I/O, and events. Created via <code>createTerm()</code>, passed to <code>render()</code> or <code>run()</code>. Everything flows through Term.</p><p><strong>AgNode</strong> — The <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> tree. <a href="https://react.dev/reference/react/Component" class="hover-link" data-tooltip="React&#39;s pluggable rendering backend — Silvery uses a custom reconciler for terminal output" target="_blank" rel="noopener">React reconciler</a> maps each React component to an AgNode. AgNodes carry box props, styles, layout results, and content. The <span class="glossary-hint" data-tooltip="React&#39;s engine for diffing virtual trees and applying minimal updates to the output">reconciler</span>, layout engine, and renderer all operate on AgNode trees.</p><p><strong><span class="glossary-hint" data-tooltip="Immutable render output — text, ANSI, cell-level queries with resolved RGB colors">TextFrame</span></strong> — Immutable snapshot of rendered output. Public read API: <code>text</code> (plain), <code>ansi</code> (styled), <code>lines</code> (per-line), <code>cell(col, row)</code> (resolved RGB, bold/dim/italic, underline, hyperlink). <code>App</code> implements <span class="glossary-hint" data-tooltip="Immutable render output — text, ANSI, cell-level queries with resolved RGB colors">TextFrame</span> — <code>app.text</code>, <code>app.cell()</code>, etc. work directly.</p><p><strong><a href="https://beorn.codes/flexily" class="hover-link" data-tooltip="Pure JavaScript flexbox layout engine — powers Silvery&#39;s layout system" target="_blank" rel="noopener">Flexily</a></strong> — Pure JS flexbox layout engine. Zero dependencies, <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a>-compatible API, 1.5-5.5x faster. Pluggable via adapters — swap with <code>SILVERY_ENGINE=yoga</code>. Used internally; apps don&#39;t interact with it directly.</p><h2 id="package-map" tabindex="-1">Package Map <a class="header-anchor" href="#package-map" aria-label="Permalink to &quot;Package Map&quot;">​</a></h2><p>Silvery is a monorepo. Internal packages (private, re-exported via barrel):</p><ul><li><code>@silvery/ag</code> — Core types: AgNode, BoxProps, keys, focus management, <span class="glossary-hint" data-tooltip="Immutable render output — text, ANSI, cell-level queries with resolved RGB colors">TextFrame</span></li><li><code>@silvery/ag-react</code> — <a href="https://react.dev/reference/react/Component" class="hover-link" data-tooltip="React&#39;s pluggable rendering backend — Silvery uses a custom reconciler for terminal output" target="_blank" rel="noopener">React reconciler</a> + hooks + UI components (<a href="/api/box" class="hover-link" data-tooltip="Primary layout component — CSS flexbox container with borders, padding, scrolling">Box</a>, <a href="/api/text" class="hover-link" data-tooltip="Styled text component with color, bold, italic, underline, and wrapping">Text</a>, <a href="/api/select-list" class="hover-link" data-tooltip="Interactive keyboard-navigable list — j/k, arrows, Enter, type-ahead search">SelectList</a>, <a href="/api/text-input" class="hover-link" data-tooltip="Single-line text input with built-in readline (Ctrl+A/E/K/U, Alt+B/F)">TextInput</a>, <a href="/api/virtual-list" class="hover-link" data-tooltip="Efficient rendering for large lists — only visible items are mounted">VirtualList</a>, etc.)</li><li><code>@silvery/ag-term</code> — Terminal runtime: Term, <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> pipeline, ANSI output, buffer diffing</li><li><code>@silvery/theme</code> — 38 semantic color palettes, <a href="/components/ThemeProvider" class="hover-link" data-tooltip="React context provider that sets the active color theme for all descendants">ThemeProvider</a>, theme CLI</li><li><code>@silvery/ink</code> — <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a>/Chalk compatibility layers</li></ul><p>Public packages (users install directly):</p><ul><li><code>silvery</code> — Main barrel: components, hooks, <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>, types</li><li><code>silvery/runtime</code> — <code>run()</code>, <code>useInput</code>, <code>createRuntime</code></li><li><code>silvery/theme</code> — <code>ThemeProvider</code>, <code>useTheme</code>, palettes</li><li><code>silvery/ui</code> — Component library (progress, CLI, forms, display)</li><li><code>@silvery/create</code> — App composition: <code>createApp</code>, <code>pipe</code>, <code>withApp</code>, <span class="glossary-hint" data-tooltip="The Elm Architecture — (action, state) → [state, effects] pattern for structured interactive state">TEA</span> store, zustand</li><li><code>@silvery/headless</code> — Pure state machines: <a href="/api/select-list" class="hover-link" data-tooltip="Interactive keyboard-navigable list — j/k, arrows, Enter, type-ahead search">SelectList</a>, Readline (no React, no rendering)</li><li><code>@silvery/commands</code> — Command registry, keymaps, invocation</li><li><code>@silvery/test</code> — Virtual renderer + termless integration for testing</li><li><code>@silvery/scope</code> — Structured concurrency: <code>createScope</code>, cancellation</li><li><code>@silvery/signals</code> — Reactive signals (alien-signals wrapper)</li><li><code>@silvery/ansi</code> — ANSI utilities, color detection, theme derivation</li><li><code>@silvery/color</code> — Pure color math: RGB/HSL/hex conversion, contrast</li><li><code>@silvery/commander</code> — Commander.js integration with colorized help</li><li><code>@silvery/model</code> — Optional DI model factories</li></ul><h2 id="component-hook-model" tabindex="-1">Component &amp; Hook Model <a class="header-anchor" href="#component-hook-model" aria-label="Permalink to &quot;Component &amp; Hook Model&quot;">​</a></h2><p><strong>Core components</strong> (from <code>@silvery/ag-react</code>):</p><ul><li><code>Box</code> — Flexbox container (the <code>&lt;div&gt;</code> of silvery)</li><li><code>Text</code> — Styled text content</li><li><code>Fill</code> — Flexible spacer</li><li><code>SelectList</code> — Interactive list with j/k/arrows/Enter (not manual cursor tracking)</li><li><code>TextInput</code> — <a href="/api/text" class="hover-link" data-tooltip="Styled text component with color, bold, italic, underline, and wrapping">Text</a> entry with readline (Ctrl+A/E/K/U, Alt+B/F) (not manual key handling)</li><li><code>VirtualList</code> — Virtualized scrolling for large lists</li><li><code>Table</code> — Tabular layout</li><li><code>ProgressBar</code>, <code>Spinner</code> — Progress indicators</li></ul><p><strong>Key hooks</strong>:</p><ul><li><code>useInput(handler)</code> — Keyboard/mouse input</li><li><code>useLayout()</code> — Current node&#39;s layout rect</li><li><code>useBoxRect()</code> / <code>useScrollRect()</code> — Content and screen-relative rects</li><li><code>useFocusable()</code> / <code>useFocusManager()</code> — Focus management</li><li><code>useVirtualization()</code> — Virtual scrolling state</li><li><code>useScrollRegion()</code> — Scroll containers</li><li><code>useCursor()</code> — Terminal cursor control</li><li><code>useEditContext()</code> — <a href="/api/text" class="hover-link" data-tooltip="Styled text component with color, bold, italic, underline, and wrapping">Text</a> editing with readline ops (cut/copy/paste/undo)</li><li><code>useApp()</code> — App-level state (zustand store)</li></ul><h2 id="the-silvery-way" tabindex="-1">The Silvery Way <a class="header-anchor" href="#the-silvery-way" aria-label="Permalink to &quot;The Silvery Way&quot;">​</a></h2><p><a href="./guide/the-silvery-way.html">Full manifesto: docs/guide/the-silvery-way.md</a></p><p>Core principle: <strong>always use canonical high-level components, never manual low-level equivalents.</strong></p><ul><li>Lists → <code>SelectList</code> (not manual <code>useInput()</code> + <code>useState</code> cursor)</li><li><a href="/api/text" class="hover-link" data-tooltip="Styled text component with color, bold, italic, underline, and wrapping">Text</a> entry → <code>TextInput</code> (not manual key handling)</li><li>Focus → <code>focusScope</code> on <a href="/api/box" class="hover-link" data-tooltip="Primary layout component — CSS flexbox container with borders, padding, scrolling">Box</a> (not manual focus state)</li><li>Large lists → <code>VirtualList</code> (not manual scroll offset)</li><li>Theme colors → <code>$primary</code>, <code>$muted</code> semantic tokens (not hardcoded ANSI)</li><li>Progress → <code>ProgressBar</code> / <code>Spinner</code> (not manual animation)</li></ul><p>Cursor convention: <a href="/api/text-input" class="hover-link" data-tooltip="Single-line text input with built-in readline (Ctrl+A/E/K/U, Alt+B/F)">TextInput</a>/<a href="/api/text-area" class="hover-link" data-tooltip="Multi-line text editing with cursor movement, selection, and word wrap">TextArea</a> use real terminal cursor when focused, fake (inverse/underline) when unfocused. No <code>realCursor</code> prop — this is just how it works.</p><h2 id="app-composition-layers" tabindex="-1">App Composition Layers <a class="header-anchor" href="#app-composition-layers" aria-label="Permalink to &quot;App Composition Layers&quot;">​</a></h2><p>Three levels, from simple to full-featured:</p><ol><li><strong><code>render(&lt;App /&gt;, term)</code></strong> — One-shot <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>. No input handling, no app lifecycle.</li><li><strong><code>run(&lt;App /&gt;, term)</code></strong> — Full app: input handling, <code>useInput</code>, <code>useExit</code>, graceful shutdown.</li><li><strong><code>createApp(config)</code></strong> — Multi-provider composition: zustand store, <span class="glossary-hint" data-tooltip="The Elm Architecture — (action, state) → [state, effects] pattern for structured interactive state">TEA</span> state machines, commands, plugins, <code>pipe()</code> for middleware.</li></ol><p>Complex applications use level 3 (<code>createApp</code>) for multi-provider composition.</p><h2 id="code-style" tabindex="-1">Code Style <a class="header-anchor" href="#code-style" aria-label="Permalink to &quot;Code Style&quot;">​</a></h2><p>Factory functions, <code>using</code> cleanup, no classes, no globals. ESM imports only. TypeScript strict mode. Raw <code>.ts</code> source published to npm (no build step — Node.js 23.6+ strips types natively).</p>`,36)])])}const m=t(i,[["render",l]]);export{h as __pageData,m as default};
